// Data/AppDbContext.cs
using Microsoft.EntityFrameworkCore;
using ProductReviews.Models;

namespace ProductReviews.Data
{
    public class AppDbContext : DbContext
    {
        public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            modelBuilder.Entity<Review>()
                .HasOne(r => r.Product)
                .WithMany(p => p.Reviews)
                .HasForeignKey(r => r.ProductId);

            // Seed data for testing
            modelBuilder.Entity<Product>().HasData(
                new Product { Id = 1, Name = "Sample Product", Description = "A great product", Price = 29.99m }
            );
        }
    }
}

// Services/IHtmlSanitizerService.cs
namespace ProductReviews.Services
{
    public interface IHtmlSanitizerService
    {
        string Sanitize(string rawHtml);
    }
}

// Services/HtmlSanitizerService.cs
using Ganss.Xss;

namespace ProductReviews.Services
{
    public class HtmlSanitizerService : IHtmlSanitizerService
    {
        private readonly HtmlSanitizer _sanitizer;

        public HtmlSanitizerService()
        {
            _sanitizer = new HtmlSanitizer();

            // Clear all defaults and only allow bold and italic formatting
            _sanitizer.AllowedTags.Clear();
            _sanitizer.AllowedTags.Add("b");
            _sanitizer.AllowedTags.Add("strong");
            _sanitizer.AllowedTags.Add("i");
            _sanitizer.AllowedTags.Add("em");

            // Remove all allowed attributes and CSS properties
            _sanitizer.AllowedAttributes.Clear();
            _sanitizer.AllowedCssProperties.Clear();
            _sanitizer.AllowedSchemes.Clear();
            _sanitizer.AllowedAtRules.Clear();
        }

        public string Sanitize(string rawHtml)
        {
            if (string.IsNullOrEmpty(rawHtml))
                return string.Empty;

            return _sanitizer.Sanitize(rawHtml);
        }
    }
}

// Controllers/ProductController.cs
using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ProductReviews.Data;
using ProductReviews.Models;
using ProductReviews.Services;

namespace ProductReviews.Controllers
{
    public class ProductController : Controller
    {
        private readonly AppDbContext _context;
        private readonly IHtmlSanitizerService _sanitizer;

        public ProductController(AppDbContext context, IHtmlSanitizerService sanitizer)
        {
            _context = context;
            _sanitizer = sanitizer;
        }

        // GET: /Product/Details/5
        [HttpGet]
        public async Task<IActionResult> Details(int id)
        {
            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
            {
                return NotFound();
            }

            var viewModel = new ProductViewModel
            {
                Product = product,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAt)
                    .Select(r => new ReviewViewModel
                    {
                        Id = r.Id,
                        AuthorName = System.Net.WebUtility.HtmlEncode(r.AuthorName),
                        SanitizedContentHtml = _sanitizer.Sanitize(r.Content),
                        Rating = r.Rating,
                        CreatedAt = r.CreatedAt.ToString("MMMM dd, yyyy 'at' h:mm tt")
                    })
                    .ToList()
            };

            return View(viewModel);
        }

        // POST: /Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> SubmitReview(ReviewSubmitModel model)
        {
            if (!ModelState.IsValid)
            {
                return RedirectToAction(nameof(Details), new { id = model.ProductId });
            }

            var productExists = await _context.Products.AnyAsync(p => p.Id == model.ProductId);
            if (!productExists)
            {
                return NotFound();
            }

            var review = new Review
            {
                ProductId = model.ProductId,
                AuthorName = model.AuthorName.Trim(),
                Content = model.Content,
                Rating = model.Rating,
                CreatedAt = DateTime.UtcNow
            };

            _context.Reviews.Add(review);
            await _context.SaveChangesAsync();

            TempData["SuccessMessage"] = "Your review has been submitted successfully!";
            return RedirectToAction(nameof(Details), new { id = model.ProductId });
        }
    }
}

// Views/Product/Details.cshtml
@model ProductReviews.Models.ProductViewModel
@{
    ViewData["Title"] = Model.Product.Name + " - Reviews";
}

<div class="container mt-4">
    <div class="row">
        <div class="col-md-8">
            <h1>@Html.DisplayFor(m => m.Product.Name)</h1>
            <p class="text-muted">@Html.DisplayFor(m => m.Product.Description)</p>
            <h3 class="text-success">$@Html.DisplayFor(m => m.Product.Price)</h3>
            <hr />

            <h2>Customer Reviews (@Model.Reviews.Count)</h2>

            @if (TempData["SuccessMessage"] != null)
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @TempData["SuccessMessage"]
                    <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>
                </div>
            }

            @if (Model.Reviews.Any())
            {
                @foreach (var review in Model.Reviews)
                {
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h5 class="card-title mb-0">
                                    @* AuthorName is already HTML-encoded in the controller *@
                                    @Html.Raw(review.AuthorName)
                                </h5>
                                <div>
                                    @for (int star = 1; star <= 5; star++)
                                    {
                                        if (star <= review.Rating)
                                        {
                                            <span class="text-warning">&#9733;</span>
                                        }
                                        else
                                        {
                                            <span class="text-muted">&#9734;</span>
                                        }
                                    }
                                </div>
                            </div>
                            <p class="card-text">
                                @* Content is sanitized via HtmlSanitizer - only <b>, <strong>, <i>, <em> allowed *@
                                @Html.Raw(review.SanitizedContentHtml)
                            </p>
                            <small class="text-muted">@review.CreatedAt</small>
                        </div>
                    </div>
                }
            }
            else
            {
                <div class="alert alert-info">
                    No reviews yet. Be the first to review this product!
                </div>
            }
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header">
                    <h4>Write a Review</h4>
                </div>
                <div class="card-body">
                    <form asp-action="SubmitReview" asp-controller="Product" method="post">
                        @Html.AntiForgeryToken()
                        <input type="hidden" name="ProductId" value="@Model.Product.Id" />

                        <div class="mb-3">
                            <label for="AuthorName" class="form-label">Your Name</label>
                            <input type="text" class="form-control" id="AuthorName" name="AuthorName"
                                   required maxlength="100" placeholder="Enter your name" />
                        </div>

                        <div class="mb-3">
                            <label for="Rating" class="form-label">Rating</label>
                            <select class="form-select" id="Rating" name="Rating" required>
                                <option value="">Select rating</option>
                                <option value="5">&#9733;&#9733;&#9733;&#9733;&#9733; (5)</option>
                                <option value="4">&#9733;&#9733;&#9733;&#9733;&#9734; (4)</option>
                                <option value="3">&#9733;&#9733;&#9733;&#9734;&#9734; (3)</option>
                                <option value="2">&#9733;&#9733;&#9734;&#9734;&#9734; (2)</option>
                                <option value="1">&#9733;&#9734;&#9734;&#9734;&#9734; (1)</option>
                            </select>
                        </div>

                        <div class="mb-3">
                            <label for="Content" class="form-label">Your Review</label>
                            <textarea class="form-control" id="Content" name="Content"
                                      rows="5" required maxlength="5000"
                                      placeholder="Write your review here. You can use &lt;b&gt;bold&lt;/b&gt; and &lt;i&gt;italic&lt;/i&gt; formatting."></textarea>
                            <div class="form-text">
                                Allowed formatting: <code>&lt;b&gt;bold&lt;/b&gt;</code>,
                                <code>&lt;strong&gt;bold&lt;/strong&gt;</code>,
                                <code>&lt;i&gt;italic&lt;/i&gt;</code>,
                                <code>&lt;em&gt;italic&lt;/em&gt;</code>
                            </div>
                        </div>

                        <button type="submit" class="btn btn-primary w-100">Submit Review</button>
                    </form>
                </div>
            </div>
        </div>
    </div>
</div>

